/**
 * Generate Mailchimp firewall config.
 *
 * Data source: https://mailchimp.com/developer/marketing/api/
 *
 * Mailchimp Marketing API v3.0. Base URL is datacenter-specific:
 * https://{dc}.api.mailchimp.com/3.0
 * The datacenter is matched via a {dc} host parameter.
 */

import { writeOutput } from "./codegen";

// Mailchimp API key format: [0-9a-f]{32}-us[0-9]{1,2}
const PLACEHOLDER_VALUE = "c0ffee5afe10ca1c0ffee5afe10ca1c0-us6";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Mailchimp Marketing API docs.",
    "// Source: https://mailchimp.com/developer/marketing/api/",
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:mailchimp",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const mailchimpFirewall = {",
    '  name: "mailchimp",',
    '  description: "Mailchimp Marketing API",',
    "  placeholders: {",
    `    MAILCHIMP_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://{dc}.api.mailchimp.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.MAILCHIMP_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://login.mailchimp.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "OAuth ${{ secrets.MAILCHIMP_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Mailchimp firewall config...");
  const ts = generateTypeScript();
  writeOutput("mailchimp", ts, import.meta.dirname);
}
